const raw = $input.first().json;
const data = raw.body || raw;
const required = ['candidate_id', 'job_id', 'cv_path'];
for (const field of required) {
  if (!data[field]) throw new Error('Missing required field: ' + field);
}
const cvUrl = data.cv_path;
let fileId = '';
const match = cvUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
if (match) fileId = match[1];
else if (cvUrl.includes('id=')) fileId = new URL(cvUrl).searchParams.get('id') || '';
if (!fileId) throw new Error('Cannot extract Google Drive file ID from: ' + cvUrl);
return [{ json: {
  candidate_id: data.candidate_id,
  candidate_name: data.candidate_name || '',
  job_id: data.job_id,
  job_title: data.job_title || data.division || '',
  job_description: data.job_description || '',
  key_responsibilities: data.key_responsibilities || '',
  minimum_qualifications: data.minimum_qualifications || '',
  threshold_score: parseInt(data.threshold_score) || 70,
  cv_path: cvUrl,
  division: data.division || '',
  gdrive_file_id: fileId,
  download_url: 'https://drive.google.com/uc?export=download&id=' + fileId
}}];

const cvText = ($input.first().json.text || '').trim();
if (!cvText) throw new Error('CV text extraction failed or CV is empty');
const jobData = $('Code - Validate & Extract').first().json;
const prompt = `You are an AI recruitment assistant evaluating a candidate CV for the position of "${jobData.job_title || jobData.division}" at a technology company.

## JOB INFORMATION
Position: ${jobData.job_title || jobData.division}
Description: ${jobData.job_description || 'Not provided'}
Key Responsibilities: ${jobData.key_responsibilities || 'Not specified'}
Minimum Qualifications: ${jobData.minimum_qualifications || 'Not specified'}
Minimum passing score: ${jobData.threshold_score}/100

## CANDIDATE CV
${cvText.substring(0, 6000)}

## EVALUATION INSTRUCTIONS
Evaluate how well this candidate matches the job requirements.
Respond ONLY with valid JSON, no markdown, no explanation outside the JSON:
{
  "score": <integer 0-100>,
  "reasoning": "<2-3 sentence summary>",
  "strengths": ["<strength 1>", "<strength 2>"],
  "gaps": ["<gap 1>"]
}`;
const llmBody = JSON.stringify({
  model: 'llama3.2',
  messages: [{ role: 'user', content: prompt }],
  stream: false,
  format: 'json',
  options: { temperature: 0.3 }
});
return [{ json: { ...jobData, cv_text_preview: cvText.substring(0, 200), llm_request_body: llmBody }}];

const llmResponse = $input.first().json;
const jobData = $('Code - Validate & Extract').first().json;
const content = llmResponse.message?.content || llmResponse.response || '';
let evalResult;
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  evalResult = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  console.log('Failed to parse Ollama JSON, fallback. Raw:', content);
  evalResult = { score: 50, reasoning: 'Automated review completed. Manual review recommended.', strengths: [], gaps: [] };
}
const score = Math.min(100, Math.max(0, parseInt(evalResult.score) || 0));
const threshold = jobData.threshold_score || 70;
const status = score >= threshold ? 'accepted' : 'rejected';
console.log(`Candidate ${jobData.candidate_id}: score=${score}, threshold=${threshold}, status=${status}`);
const updateBody = JSON.stringify({
  candidate_id: jobData.candidate_id,
  score,
  status,
  ai_reasoning: evalResult.reasoning || ''
});
return [{ json: {
  candidate_id: jobData.candidate_id,
  score, status, threshold,
  ai_reasoning: evalResult.reasoning || '',
  strengths: evalResult.strengths || [],
  gaps: evalResult.gaps || [],
  update_body: updateBody
}}];
